frappe.web_form.after_load = function() {
  // INJECTION: Dynamic Reference Number
  if (doc && doc.name) {
    var refEl = document.createElement('div');
    refEl.innerHTML = '<div style="margin-bottom:12px;padding:8px 16px;background:#f1f8e9;color:#33691e;border-left:4px solid #8bc34a;border-radius:6px;display:inline-block;font-weight:700;margin-right:10px;font-size:14px;">Réf. Dossier : ' + doc.name + '</div>';
    var w = document.querySelector('.web-form-wrapper') || document.querySelector('.container');
    if (w) w.prepend(refEl);
  }

  var doc = frappe.web_form.doc;
  var roles = (frappe.boot && frappe.boot.user && frappe.boot.user.roles) ? frappe.boot.user.roles : [];
  var state = (doc && (doc.workflow_state || doc.statut)) || 'Brouillon';
  var rules = {
    'signature_demandeur': { states: ['Brouillon'], roles: [] },
    'signature_chef': { states: ['En attente Chef'], roles: ['Chef Service','System Manager'] },
    'signature_audit': { states: ['En attente Audit'], roles: ['Auditeur Interne','System Manager'] },
    'signature_dga': { states: ['En attente DGA'], roles: ['DGA','Directeur Général','System Manager'] },
    'signature_magasin': { states: ['En attente Magasin'], roles: ['Chargé des Stocks','Responsable Stock','System Manager'] }
  };
  Object.keys(rules).forEach(function(field) {
    var rule = rules[field];
    var stateOk = rule.states.indexOf(state) !== -1;
    var roleOk = rule.roles.length === 0 || rule.roles.some(function(r){ return roles.indexOf(r) !== -1; });
    if (stateOk && roleOk) frappe.web_form.set_df_property(field, 'read_only', 0);
  });
  if (doc && doc.statut) {
    var cm = {'Approuv\u00e9':'#2e7d32','Rejet\u00e9':'#c62828','Brouillon':'#757575'};
    var c = cm[doc.statut] || '#e65100';
    var el = document.createElement('div');
    el.innerHTML = '<div style="margin-bottom:12px;padding:8px 16px;background:'+c+';color:#fff;border-radius:6px;display:inline-block;font-weight:700;">\u00c9tat\u00a0: '+doc.statut+'</div>';
    var w = document.querySelector('.web-form-wrapper') || document.querySelector('.container');
    if (w) w.prepend(el);
  }
};
frappe.web_form.on('load', function(){
  var doc = frappe.web_form.doc;
  if (!doc.demandeur_nom && frappe.session && frappe.session.user) {
    frappe.call({ method:'frappe.client.get_value', args:{ doctype:'Employee', filters:{ user_id: frappe.session.user }, fieldname:'employee_name' }, callback:function(r){ if(r.message && r.message.employee_name) frappe.web_form.set_value('demandeur_nom', r.message.employee_name); } });
  }
});
frappe.web_form.on('customer_manuel', function(field, value){
  if (!value) return;
  var d = frappe.web_form.doc;
  if (d && d.customer) return;
  if (window.__kya_customer_prompt_shown) return;
  window.__kya_customer_prompt_shown = true;
  frappe.confirm('Le client "' + value + '" n\'existe pas dans la base.\n\nVoulez-vous l\'enregistrer maintenant ?\n\n(OK = ouvrir le formulaire client dans un nouvel onglet ; Annuler = continuer sans enregistrer)', function(){
    var url = '/app/customer/new?customer_name=' + encodeURIComponent(value);
    window.open(url, '_blank');
  });
});

/* KYA-AUTO-DATE-DEFAULT */
frappe.web_form.on('load', function(){
  if (!frappe.web_form.doc.date_sortie) frappe.web_form.set_value('date_sortie', frappe.datetime.get_today());
});
